form:Form.form:Scripts:
		function LoadForm()
{
	if (Ctrl("main").GetMode()=="LIST")
		ChangeSelect(Ctrl("LIST"));	
}

function Find()
{
	FiltroSimultaneo();
}

function FiltrarEstado()
{
	FiltroSimultaneo();
}

function ChangeSelect(lvObj)
{
	CtrlEnabled("EDIT", (lvObj.GetSelectAttrValue("c_estado")=="D"?false:true));	
}                                                      

function FiltroSimultaneo()
	{
		Ctrl("LIST").shownRegs = new Array();

		//Recupero la informacion del formulario                
		var colEstado = "c_estado";
		var valEstado = Ctrl("estado").GetCValue();
		var valBuscar = Ctrl("iter_search").GetCValue()

		//Si los dos filtros estan vacios
		if(valBuscar=="" && valEstado=="")
			for (var i = 0; i < Ctrl("LIST").allRegs.length; i++)
				Ctrl("LIST").shownRegs.push(Ctrl("LIST").allRegs[i]); 

		//Si solo completo el filtro buscar		
		else if (valEstado=="" && valBuscar!="")
				Ctrl("LIST").filter("",valBuscar);

		//Si solo completo el filtro estado
		else if(valEstado!="" && valBuscar=="")
				Ctrl("LIST").filter(colEstado,valEstado);

		//Si completo ambos filtros 
		else if(valEstado!="" && valBuscar!="")
		{     
		var att, attcon;
		for (var i = 0; i < Ctrl("LIST").allRegs.length; i++)
			for (var c = 0; c < Ctrl("LIST").columns.length; c++)
				{
					att = Ctrl("LIST").allRegs[i].attributes.getNamedItem(Ctrl("LIST").columns[c].attribName);
					if (att?false:true) continue;

					//Preparando la busqueda					
					switch (Ctrl("LIST").columns[c].tipo)
					{
						case "number":
							resp = parseNumericValue(att.value, Ctrl("LIST").columns[c].format);
							break;
						case "datetime":
							resp = parseDatetimeValue(att.value, Ctrl("LIST").columns[c].format);
							break;
						case "string":
							resp = att.value;
							break;
						case "enum": case "combo": 
							resp = parseEnumValue(att.value, Ctrl("LIST").columns[c].opciones);
							break;
						case "fk": 
							resp = parseFkValue(att.value, Ctrl("LIST").columns[c].m_flow, Ctrl("LIST").columns[c].m_action, Ctrl("LIST"));
							break;
						default:
							resp="";
						break;
					}
					if (resp=="") continue;

					//Buscando
					if (resp.toUpperCase().indexOf(valBuscar.toUpperCase()) != -1 && (Ctrl("LIST").allRegs[i].attributes.getNamedItem(g_CTRLs[colEstado].attribName).value).indexOf(valEstado) != -1)
					{
						Ctrl("LIST").shownRegs.push(Ctrl("LIST").allRegs[i]);
						break;
					}
				}
		}

		Ctrl("LIST").sort();      

}
